customCss:
@import url('https://fonts.googleapis.com/css2?family=Bricolage+Grotesque:wght@400;500;600;700&family=Playfair+Display:wght@600;700;800&display=swap');
:root { --font-body: 'Bricolage Grotesque', sans-serif; --font-display: 'Playfair Display', serif; --radius: 8px; --ambient-glow-opacity: 0.2; }

/* ── Ember noise texture overlay ── */
body::after { content: ''; position: fixed; inset: 0; opacity: 0.025; background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E"); pointer-events: none; z-index: 9999; }

/* ── Cards: warm glow on hover ── */
.media-card-image { border: 1px solid rgba(255,145,0,0.1); transition: border-color 0.4s, box-shadow 0.4s; }
.media-card:hover .media-card-image { border-color: rgba(255,145,0,0.35); box-shadow: 0 8px 24px rgba(255,145,0,0.2), 0 2px 8px rgba(255,100,0,0.15); }
.media-card:hover { transform: translateY(-3px); }

/* ── Sidebar: warm wood panel feel ── */
aside { border-right: 1px solid rgba(255,145,0,0.12) !important; background: linear-gradient(180deg, rgba(16,10,4,1) 0%, rgba(20,14,6,1) 100%); }
.sidebar-logo-icon { background: linear-gradient(135deg, rgba(255,145,0,0.15), rgba(255,204,0,0.1)); border: 1px solid rgba(255,145,0,0.25); }

/* ── Section headers: serif display ── */
.section-header { font-family: 'Playfair Display', serif; font-weight: 600; font-size: 1rem; letter-spacing: 0.02em; }

/* ── Page titles: bold serif ── */
.page-title { font-family: 'Playfair Display', serif; font-weight: 800; }

/* ── Badges: warm tinted ── */
.metadata-badge { border: 1px solid rgba(255,145,0,0.15); background: rgba(255,145,0,0.06); }

/* ── Pill buttons: warm gradient ── */
.pill-primary { background: linear-gradient(135deg, #ff9100, #ffab40) !important; box-shadow: 0 4px 14px rgba(255,145,0,0.3); }
.pill-primary:hover { box-shadow: 0 6px 22px rgba(255,145,0,0.45); }

/* ── Glass effects: warm amber tint ── */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(255,145,0,0.08); }

/* ── Surface panels: warm border ── */
.surface-panel { border: 1px solid rgba(255,145,0,0.08); }

/* ── Hero: warm cinematic grading ── */
:root { --hero-backdrop-brightness: 0.7; --hero-backdrop-saturate: 1.2; --hero-text-shadow: 0 18px 50px rgba(255,100,0,0.3); }

/* ── Warm shadows everywhere ── */
.surface-panel, .glass, .glass-subtle { box-shadow: 0 4px 12px rgba(80,40,0,0.2); }

/* ── Progress bars: ember gradient ── */
.progress-fill { background: linear-gradient(90deg, #ff5722, #ff9100, #ffcc00) !important; box-shadow: 0 0 8px rgba(255,145,0,0.4); }

/* ── Ambient glow: pulsing ember ── */
@keyframes ember-pulse { 0%, 100% { opacity: 0.2; } 50% { opacity: 0.28; } }
.ambient-glow { animation: ember-pulse 4s ease-in-out infinite; }

/* ── Tab bar: warm underline ── */
.tab-active { border-bottom: 2px solid #ff9100; box-shadow: 0 2px 8px rgba(255,145,0,0.25); }
